INSERT OR IGNORE INTO dictionary (slug, term, term_en, category, short_desc, full_desc, related_treatments) VALUES
('dental-implant','임플란트','dental implant','implant','인공치아 뿌리를 잇몸뼈에 심어 자연치처럼 기능을 회복시키는 치료','상실된 치아를 대체하기 위해 티타늄 소재의 인공 치근을 턱뼈에 식립하고, 그 위에 보철물을 연결하는 현대 치과의 대표 술식입니다. 씹는 힘과 심미성을 모두 회복할 수 있습니다.','["implant","prosthetics"]'),
('fixture','픽스쳐','fixture','implant','임플란트의 인공 치근 부분','잇몸뼈 안에 직접 식립되는 나사 모양의 티타늄 부품으로, 임플란트의 가장 기초가 되는 부분입니다.','["implant","prosthetics"]'),
